code.C++:
#include <iostream>
using namespace std;

int main() {
    int n;
    cin >> n;
    int values[n];
    for (int i = 0; i < n; ++i) {
        cin >> values[i];
    }

    for (int x : values) {
        if (x > 10) {
            continue;
        }
        cout << x * x << endl;
    }
    return 0;
}

